import{_ as a,a as e,b as d}from"./chunks/配置渠道内容.HzNkdrom.js";import{_ as i,o as r,c as o,a2 as l}from"./chunks/framework.DnrXFDHb.js";const P=JSON.parse('{"title":"GitLab Packages チャンネルの追加","description":"","frontmatter":{},"headers":[],"relativePath":"ja-JP/upload/gitlab-packages.md","filePath":"ja-JP/upload/gitlab-packages.md","lastUpdated":1781962217000}'),s={name:"ja-JP/upload/gitlab-packages.md"};function c(n,t,b,h,g,p){return r(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="gitlab-packages-チャンネルの追加" tabindex="-1">GitLab Packages チャンネルの追加 <a class="header-anchor" href="#gitlab-packages-チャンネルの追加" aria-label="Permalink to &quot;GitLab Packages チャンネルの追加&quot;">​</a></h1><p>GitLab Packages チャンネルは、GitLab の Generic Package Registry を保存先として使います。</p><h2 id="事前に用意するもの" tabindex="-1">事前に用意するもの <a class="header-anchor" href="#事前に用意するもの" aria-label="Permalink to &quot;事前に用意するもの&quot;">​</a></h2><table tabindex="0"><thead><tr><th>必要なもの</th><th>用途</th></tr></thead><tbody><tr><td>GitLab アカウント</td><td>プロジェクトと Token を管理します</td></tr><tr><td>GitLab プロジェクト</td><td>Package を保存する場所</td></tr><tr><td>Access Token</td><td>Package Registry へアップロードするため</td></tr><tr><td>Project ID</td><td>ImgBed から対象プロジェクトを指定します</td></tr></tbody></table><h2 id="token-を作成する" tabindex="-1">Token を作成する <a class="header-anchor" href="#token-を作成する" aria-label="Permalink to &quot;Token を作成する&quot;">​</a></h2><p>GitLab の設定から Access Token を作成します。必要な権限を選びます。</p><p><img src="'+a+'" alt="旧版 Token 生成" loading="lazy"></p><p>アップロードと読み取りに必要な権限を付与します。</p><p><img src="'+e+'" alt="Token 権限" loading="lazy"></p><p>Token は作成直後にしか確認できない場合があります。必ずコピーして安全に保管してください。</p><h2 id="imgbed-へ入力する" tabindex="-1">ImgBed へ入力する <a class="header-anchor" href="#imgbed-へ入力する" aria-label="Permalink to &quot;ImgBed へ入力する&quot;">​</a></h2><p>アップロード設定で <code>GitLab Packages</code> を選びます。</p><table tabindex="0"><thead><tr><th>項目</th><th>入力内容</th></tr></thead><tbody><tr><td>チャンネル名</td><td>例：<code>GitLab Packages</code></td></tr><tr><td>GitLab Host</td><td><code>https://gitlab.com</code> または自前 GitLab の URL</td></tr><tr><td>Project ID</td><td>対象プロジェクトの ID</td></tr><tr><td>Token</td><td>作成した Access Token</td></tr><tr><td>Package Name</td><td>パッケージ名</td></tr><tr><td>Version</td><td>バージョン名</td></tr><tr><td>保存パス</td><td>任意</td></tr></tbody></table><p><img src="'+d+'" alt="GitLab 設定" loading="lazy"></p><h2 id="確認方法" tabindex="-1">確認方法 <a class="header-anchor" href="#確認方法" aria-label="Permalink to &quot;確認方法&quot;">​</a></h2><ol><li>保存後にチャンネルカードが表示される。</li><li>テストファイルをアップロードする。</li><li>GitLab の Package Registry にファイルが登録される。</li><li>ImgBed のリンクからアクセスできる。</li></ol><h2 id="よくある原因" tabindex="-1">よくある原因 <a class="header-anchor" href="#よくある原因" aria-label="Permalink to &quot;よくある原因&quot;">​</a></h2><ul><li>Project ID が間違っている。</li><li>Token に Package Registry への書き込み権限がない。</li><li>自前 GitLab の Host URL が正しくない。</li><li>プロジェクト側で Package Registry が無効になっている。</li></ul>',18)])])}const _=i(s,[["render",c]]);export{P as __pageData,_ as default};
